  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUv-.5) * uAspect.xy;

vec2 uv6 = uv1;
float z = 1*length(uv1)+rand_frame*13;
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)/d,-2,2);

vUv += rs/16;

uv6 = (uv1)*(1 + 0*q27);
//vUv = multiply(vUv,mat2(_qb));


uv6 = vUv.yx;
mus = q1*cos(uv6.y*44)-(cos(uv6.x*82));
float mod = q28*lum(mus) + 1-q28*lum(mus);
//mus = mix(mus.gbr,mus*vec3 (.9,.9,1),mod);

vec3 blur = GetBlur2(fract(vUv));

vec3 crisp= texture(sampler_main,vUv);

vec3 ret1 = crisp + .1*mus *(1+texture(sampler_noise_lq,vUv/16+uTime/100));
ret1 = ret1 * .98 -  .025;
q25 = q24*1;
ret = q25 * ret1 + (1-q25)*GetPixel(vUvOriginal);

